import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Sparkles, Loader2 } from 'lucide-react';

// 🔑 DEBUG: Check if the key exists
const API_KEY = process.env.REACT_APP_GEMINI_API_KEY; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "DEBUG MODE: I will print errors to the Console (F12). Ask me something!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto-scroll chat
  useEffect(() => {
    if (isOpen) {
       messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isThinking, isOpen]);

  // --- THE BRAIN (Logic) ---
  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    console.log("--------------------------------------------------");
    console.log("🤖 STARTING AI REQUEST...");

    try {
      // 🕵️ DEBUG 1: Check API Key
      if (!API_KEY) {
        console.error("❌ FATAL ERROR: API Key is MISSING or UNDEFINED.");
        console.error("Check .env file and ensure it starts with REACT_APP_");
        throw new Error("API Key is missing");
      }
      console.log("✅ API Key detected:", API_KEY.substring(0, 5) + "..."); 

      // 🕵️ DEBUG 2: Initialize Client
      console.log("⚙️ Initializing GoogleGenerativeAI...");
      const genAI = new GoogleGenerativeAI(API_KEY);
      
      // 🕵️ DEBUG 3: Model Selection
      // Using 'gemini-pro' as it is the most stable
      console.log("⚙️ Connecting to Model: gemini-pro...");
      const model = genAI.getGenerativeModel({ model: "gemini-pro" });

      // 2. The Context System
      const systemContext = `
        You are "CampusBot", the AI assistant for ${collegeData?.collegeInfo?.name || "NIMIT"}.
        INSTRUCTIONS:
        1. If asked about College/NIMIT, use provided data.
        2. If asked about Code/Math/General, answer as a helpful expert AI.
      `;

      console.log("📤 Sending Prompt to Google...");
      const result = await model.generateContent(`${systemContext}\n\nUser Question: ${userMsg.text}\nAnswer:`);
      
      console.log("📥 Received Result Object:", result);
      const response = await result.response;
      console.log("📥 Extracted Response:", response);
      
      const text = response.text();
      console.log("✅ Final Text:", text);

      // 3. Add AI Response
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: text, isBot: true }]);
      
    } catch (error) {
      // 🚨 THIS IS WHAT WE NEED TO SEE
      console.error("🔥 AI CRASH REPORT 🔥");
      console.error("Error Name:", error.name);
      console.error("Error Message:", error.message);
      console.error("Full Error Object:", error);
      
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: `🔥 DEBUG ERROR: ${error.message} (Check Console F12)`, isBot: true }]);
    }
  };

  // --- THE UI (Visuals) ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      
      {!isOpen && (
        <button 
          onClick={onOpen}
          className="relative group flex items-center justify-center w-14 h-14 bg-gradient-to-tr from-indigo-600 to-purple-600 rounded-full shadow-[0_0_30px_rgba(99,102,241,0.5)] hover:scale-110 transition-all duration-300 border border-white/20 animate-bounce"
        >
          <Bot className="w-6 h-6 text-white" />
        </button>
      )}

      {isOpen && (
        <div className="w-[380px] h-[600px] max-h-[80vh] bg-[#0a0a0a]/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-[0_0_50px_rgba(0,0,0,0.8)] flex flex-col overflow-hidden animate-fade-in-up">
          
          <div className="bg-white/5 border-b border-white/10 p-4 flex items-center justify-between">
            <h3 className="text-white font-bold">CampusBot (Debug Mode)</h3>
            <button onClick={onClose} className="p-2 text-gray-400 hover:text-white"><X className="w-5 h-5" /></button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[80%] p-3.5 text-sm leading-relaxed shadow-lg ${!msg.isBot ? 'bg-indigo-600 text-white rounded-2xl' : 'bg-white/10 text-gray-200 border border-white/5 rounded-2xl'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && <div className="text-white text-xs p-4">Analyzing Error... check Console...</div>}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-4 bg-black/40 border-t border-white/10">
            <div className="relative flex items-center">
              <input 
                type="text" 
                value={input} 
                onChange={(e) => setInput(e.target.value)} 
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask to trigger error..." 
                className="w-full bg-white/5 border border-white/10 rounded-xl pl-4 pr-12 py-3.5 text-sm text-white"
              />
              <button onClick={handleSend} disabled={isThinking || !input.trim()} className="absolute right-2 p-2 bg-indigo-600 text-white rounded-lg">
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>

        </div>
      )}
    </div>
  );
}

export default ChatBot;
